SELECT t.ticker, t.time FROM `tav2_bq.ticker` AS t WHERE (t.time >= '2020-01-01' AND t.time <= '2026-04-03') AND ((t.Volume_3M_P50*t.Price/ NULLIF(t.Inflation_7, 0))>800000000.0) AND (t.Risk_Rating <= 6) AND (t.Close> 1.13*t.Volume_Max5Y_High) AND (t.ROE_Min5Y > 0.03) AND (t.PE<=11.2) AND (t.PE >0.0) AND (t.NP_P0 > 1.2*t.NP_P1) AND (t.NP_P1 > t.NP_P2) AND (t.HI_3M_T1/ NULLIF(t.LO_3M_T1, 0)<2.2) ORDER BY t.ticker, t.time